"use client";

import { useEffect, useRef, useState } from "react";

export default function TechStack() {
  const [isVisible, setIsVisible] = useState(false);
  const ref = useRef(null);

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true);
        }
      },
      { threshold: 0.1 }
    );

    if (ref.current) {
      observer.observe(ref.current);
    }

    return () => observer.disconnect();
  }, []);

  const technologies = [
    {
      category: "Frontend",
      items: ["React", "Next.js", "TypeScript", "TailwindCSS",],
    },
    {
      category: "State & Data",
      items: ["Redux", "Zustand"],
    },
    {
      category: "Tools & Testing",
      items: ["Jest", "React Testing Library", "Vitest"],
    },
    {
      category: "Backend",
      items: ["Node", "MongoDB", "ExpressJS", "SQL"],
    },
  ];

  return (
    <section ref={ref} className="py-20 px-6 bg-card/50">
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold text-foreground mb-4">
            Tech Stack
          </h2>
          <p className="text-muted-foreground text-lg">
            The tools and technologies I use to build amazing things
          </p>
        </div>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
          {technologies.map((tech, categoryIdx) => (
            <div
              key={tech.category}
              className={`group rounded-xl border border-accent/20 bg-background/50 p-6 hover:border-accent/50 hover:bg-accent/5 transition-all duration-300 hover:shadow-lg hover:shadow-accent/10 hover:-translate-y-1 cursor-default`}
              style={{
                transitionDelay: isVisible ? `${categoryIdx * 100}ms` : "0ms",
                opacity: isVisible ? 1 : 0,
                transform: isVisible ? "translateY(0)" : "translateY(20px)",
              }}
            >
              <h3 className="text-lg font-semibold text-accent mb-4 group-hover:text-white transition-colors">
                {tech.category}
              </h3>
              <ul className="space-y-3">
                {tech.items.map((item) => (
                  <li
                    key={item}
                    className="text-muted-foreground text-sm flex items-center gap-2 group-hover:text-foreground transition-colors"
                  >
                    <span className="w-1.5 h-1.5 rounded-full bg-accent group-hover:scale-150 transition-transform" />
                    {item}
                  </li>
                ))}
              </ul>
            </div>
          ))}
        </div>
      </div>
    </section>
  );
}
