'use client'

import { useState, useEffect } from 'react'
import { Menu, X, Download } from 'lucide-react'

export default function Navigation() {
  const [isOpen, setIsOpen] = useState(false)
  const [isScrolled, setIsScrolled] = useState(false)

  useEffect(() => {
    const handleScroll = () => {
      setIsScrolled(window.scrollY > 50)
    }

    window.addEventListener('scroll', handleScroll)
    return () => window.removeEventListener('scroll', handleScroll)
  }, [])

  const scrollToSection = (id: string) => {
    const element = document.getElementById(id)
    element?.scrollIntoView({ behavior: 'smooth' })
    setIsOpen(false)
  }

  const downloadResume = () => {
    const link = document.createElement('a')
    link.href = '/resume.pdf'
    link.download = 'Yusuf_Abdullahi_Resume.pdf'
    document.body.appendChild(link)
    link.click()
    document.body.removeChild(link)
  }

  const links = [
    { label: 'About', id: 'about' },
    { label: 'Projects', id: 'projects' },
    { label: 'Experience', id: 'experience' },
    { label: 'Contact', id: 'contact' },
  ]

  return (
    <nav
      className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 animate-slide-down ${
        isScrolled
          ? 'bg-background/80 backdrop-blur-md border-b border-border'
          : 'bg-transparent'
      }`}
    >
      <div className="max-w-6xl mx-auto px-6 py-4 flex justify-between items-center">
        <a
          href="#"
          className="text-2xl font-bold bg-gradient-to-r from-accent to-secondary bg-clip-text text-transparent hover:opacity-80 transition-opacity"
        >
          Yusuf
        </a>

        {/* Desktop Navigation */}
        <div className="hidden md:flex gap-8 items-center">
          {links.map((link) => (
            <button
              key={link.id}
              onClick={() => scrollToSection(link.id)}
              className="text-muted-foreground hover:text-accent transition-colors text-sm font-medium"
            >
              {link.label}
            </button>
          ))}
          <button
            onClick={downloadResume}
            className="px-4 py-2 bg-accent text-accent-foreground rounded-lg font-semibold flex items-center gap-2 hover:bg-accent/90 transition-all hover:shadow-lg hover:shadow-accent/20 text-sm"
          >
            <Download size={16} />
            Resume
          </button>
        </div>

        {/* Mobile Menu Button */}
        <button
          onClick={() => setIsOpen(!isOpen)}
          className="md:hidden text-foreground hover:text-accent transition-colors"
        >
          {isOpen ? <X size={24} /> : <Menu size={24} />}
        </button>
      </div>

      {/* Mobile Navigation */}
      {isOpen && (
        <div className="md:hidden bg-card border-b border-border">
          <div className="px-6 py-4 space-y-4">
            {links.map((link) => (
              <button
                key={link.id}
                onClick={() => scrollToSection(link.id)}
                className="block w-full text-left text-muted-foreground hover:text-accent transition-colors text-sm font-medium"
              >
                {link.label}
              </button>
            ))}
            <button
              onClick={downloadResume}
              className="w-full px-4 py-2 bg-accent text-accent-foreground rounded-lg font-semibold flex items-center justify-center gap-2 hover:bg-accent/90 transition-all text-sm mt-4"
            >
              <Download size={16} />
              Download Resume
            </button>
          </div>
        </div>
      )}
    </nav>
  )
}
