'use client'

import { useEffect, useRef, useState } from 'react'
import { ExternalLink, Github } from 'lucide-react'

export default function Projects() {
  const [isVisible, setIsVisible] = useState(false)
  const ref = useRef(null)

  useEffect(() => {
    const observer = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setIsVisible(true)
        }
      },
      { threshold: 0.1 }
    )

    if (ref.current) {
      observer.observe(ref.current)
    }

    return () => observer.disconnect()
  }, [])

  const projects = [
    {
      title: 'E-Commerce Platform',
      description:
        'Full-stack e-commerce platform with advanced filtering, checkout flow, and real-time inventory management.',
      tools: ['React', 'Next.js', 'TypeScript', 'Stripe', 'PostgreSQL'],
      image: 'bg-gradient-to-br from-blue-500 to-purple-600',
    },
    {
      title: 'Design System',
      description:
        'Component library with 50+ customizable components, comprehensive documentation, and Storybook integration.',
      tools: ['React', 'TailwindCSS', 'Storybook', 'TypeScript', 'npm'],
      image: 'bg-gradient-to-br from-emerald-500 to-teal-600',
    },
    {
      title: 'Analytics Dashboard',
      description:
        'Real-time analytics dashboard with interactive charts, data visualization, and performance metrics.',
      tools: ['React', 'Chart.js', 'Redux', 'WebSockets', 'Node.js'],
      image: 'bg-gradient-to-br from-orange-500 to-red-600',
    },
    {
      title: 'Mobile App',
      description:
        'Cross-platform mobile application built with React Native, featuring offline support and real-time sync.',
      tools: ['React Native', 'Firebase', 'Redux', 'TypeScript', 'Expo'],
      image: 'bg-gradient-to-br from-pink-500 to-rose-600',
    },
  ]

  return (
    <section
      id="projects"
      ref={ref}
      className="py-20 px-6 bg-background"
    >
      <div className="max-w-6xl mx-auto">
        <div className="text-center mb-16">
          <h2 className="text-4xl font-bold text-foreground mb-4">
            Featured Projects
          </h2>
          <p className="text-muted-foreground text-lg">
            A selection of projects I'm proud of
          </p>
        </div>

        <div className="grid md:grid-cols-2 gap-8">
          {projects.map((project, idx) => (
            <div
              key={project.title}
              className={`group rounded-xl overflow-hidden border border-accent/20 bg-card hover:border-accent/50 transition-all duration-300 hover:shadow-lg hover:shadow-accent/10 hover:-translate-y-1`}
              style={{
                transitionDelay: isVisible ? `${idx * 100}ms` : '0ms',
                opacity: isVisible ? 1 : 0,
                transform: isVisible ? 'translateY(0)' : 'translateY(20px)',
              }}
            >
              {/* Project Image */}
              <div className={`h-48 ${project.image} overflow-hidden relative`}>
                <div className="absolute inset-0 bg-black/30 group-hover:bg-black/40 transition-all" />
                <div className="absolute inset-0 flex items-center justify-center opacity-0 group-hover:opacity-100 transition-opacity">
                  <div className="flex gap-4">
                    <button className="p-3 rounded-full bg-white/20 backdrop-blur hover:bg-white/30 text-white transition-all hover:scale-110">
                      <ExternalLink size={20} />
                    </button>
                    <button className="p-3 rounded-full bg-white/20 backdrop-blur hover:bg-white/30 text-white transition-all hover:scale-110">
                      <Github size={20} />
                    </button>
                  </div>
                </div>
              </div>

              {/* Project Content */}
              <div className="p-6">
                <h3 className="text-xl font-bold text-foreground mb-2 group-hover:text-accent transition-colors">
                  {project.title}
                </h3>
                <p className="text-muted-foreground text-sm mb-4 leading-relaxed">
                  {project.description}
                </p>

                {/* Tools */}
                <div className="flex flex-wrap gap-2">
                  {project.tools.map((tool) => (
                    <span
                      key={tool}
                      className="px-3 py-1 text-xs rounded-full bg-accent/10 text-accent border border-accent/30 font-mono"
                    >
                      {tool}
                    </span>
                  ))}
                </div>
              </div>
            </div>
          ))}
        </div>
      </div>
    </section>
  )
}
